source "$(cd "$(dirname "${BASH_SOURCE[0]}")/../../.." && pwd)/tests/support/shell-test.sh"

output="$({
  pidev_nvim_output \
    +"set columns=120 lines=40 laststatus=3" \
    +"lua local defaults = require('pi-dev.config').defaults; assert(defaults.ui.width == 100); assert(defaults.ui.input_height == 10); require('pi-dev').setup({ keymaps = { enable = false }, ui = { position = 'right', width = 40, input_height = 6 } })" \
    +"lua local ui = require('pi-dev.ui'); ui.show(); local state = require('pi-dev.state'); local out_win, in_win, status_win = state.ui.output_win, state.ui.input_win, state.ui.status_win; assert(vim.api.nvim_win_is_valid(out_win)); assert(vim.api.nvim_win_is_valid(in_win)); assert(vim.api.nvim_win_is_valid(status_win), 'status separator float must exist'); local out_pos = vim.api.nvim_win_get_position(out_win); local in_pos = vim.api.nvim_win_get_position(in_win); assert(out_pos[2] == in_pos[2], ('input column %d differs from output column %d'):format(in_pos[2], out_pos[2])); assert(vim.api.nvim_win_get_width(out_win) == vim.api.nvim_win_get_width(in_win)); assert(in_pos[1] > out_pos[1], 'input must be below output inside the Pi panel'); local status_cfg = vim.api.nvim_win_get_config(status_win); assert(status_cfg.focusable == false, 'status separator must not be focusable like a normal buffer'); assert(status_cfg.relative == 'win' and status_cfg.win == out_win, 'status separator must belong to upper Pi pane'); assert(vim.bo[state.ui.output_buf].modifiable == false, 'output buffer must be read-only'); assert(vim.bo[state.ui.status_buf].modifiable == false, 'status separator buffer must be read-only'); assert(vim.bo[state.ui.input_buf].modifiable == true, 'plain input buffer must remain editable'); assert(vim.bo[state.ui.input_buf].filetype == 'text', 'Pi input must be plain text, not markdown'); local foreign = vim.api.nvim_create_buf(true, false); vim.api.nvim_buf_set_name(foreign, 'pi-dev-test-foreign'); pcall(function() vim.wo[out_win].winfixbuf = false end); vim.api.nvim_win_set_buf(out_win, foreign); ui.guard_panel_buffers(); assert(vim.api.nvim_win_get_buf(out_win) == state.ui.output_buf, 'Pi output window must restore its owned buffer'); if state.ui.file_win and vim.api.nvim_win_is_valid(state.ui.file_win) then assert(vim.api.nvim_win_get_buf(state.ui.file_win) == foreign, 'foreign file buffer should be redirected to last file window') end; pcall(vim.api.nvim_set_option_value, 'winfixbuf', true, { win = out_win }); pcall(vim.api.nvim_set_option_value, 'winfixbuf', true, { win = in_win }); pcall(vim.api.nvim_set_option_value, 'winfixbuf', true, { win = status_win }); pcall(vim.api.nvim_win_set_width, out_win, 20); pcall(vim.api.nvim_win_set_height, in_win, 2); local manual_width = vim.api.nvim_win_get_width(out_win); local manual_height = vim.api.nvim_win_get_height(in_win); ui.align(); assert(vim.api.nvim_win_get_width(out_win) == manual_width, 'align should preserve manual Pi panel width'); assert(vim.api.nvim_win_get_height(in_win) == manual_height, 'align should preserve manual Pi input height'); status_cfg = vim.api.nvim_win_get_config(status_win); assert(status_cfg.row == vim.api.nvim_win_get_height(out_win) - 1, 'status separator should sit on the last output row, one row above the lower Pi pane'); if vim.fn.exists('+winbar') == 1 then assert(vim.wo[out_win].winbar:find('Pi chat') ~= nil, 'chat winbar should title the chat surface'); assert(vim.wo[in_win].winbar:find('Pi input') ~= nil, 'input winbar should title the input surface'); assert(vim.wo[in_win].winbar:find('pi%-dev.statusline') == nil, 'Pi input title must not be rendered by live statusline expression') end; require('pi-dev.renderer').append_system(table.concat(vim.tbl_map(function(i) return 'line ' .. i end, vim.fn.range(1, 80)), '\n')); assert(vim.wait(1000, function() local cursor = vim.api.nvim_win_get_cursor(out_win); return cursor[1] == vim.api.nvim_buf_line_count(state.ui.output_buf) end), 'output should auto-scroll to bottom when focus is outside output'); ui.show_interaction({ title = 'Pick', items = { { label = 'Yes' }, { label = 'No' } } }); assert(vim.api.nvim_win_get_buf(state.ui.input_win) == state.ui.interaction_buf, 'select interaction should use separate interaction buffer'); assert(vim.bo[state.ui.interaction_buf].modifiable == false, 'select interaction buffer should be read-only'); assert(vim.bo[state.ui.input_buf].modifiable == true, 'Pi input buffer should remain editable behind interaction')"
} 2>&1)" || {
  printf '%s\n' "$output"
  exit 1
}

pidev_assert_no_nvim_errors "$output"
